/* ============================================= Chat 页面样式 继承博客主题色 Indigo (#4f46e5) ============================================= */ .chat-container { max-width: 800px; margin: 0 auto; display: flex; flex-direction: column; height: 70vh; min-height: 500px; background: var(--color-card); border: 1px solid rgba(0,0,0,0.05); border-radius: 16px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.04); } .dark .chat-container { border-color: rgba(255,255,255,0.06); box-shadow: 0 2px 12px rgba(0,0,0,0.15); } /* --- Header --- */ .chat-header { display: flex; align-items: center; justify-content: space-between; padding: 16px 20px; border-bottom: 1px solid rgba(0,0,0,0.04); flex-shrink: 0; } .dark .chat-header { border-color: rgba(255,255,255,0.04); } .chat-header-title { display: flex; align-items: center; gap: 10px; font-size: 1em; font-weight: 600; color: var(--color-text-1); } .chat-header-dot { width: 8px; height: 8px; border-radius: 50%; background: #22c55e; animation: chat-pulse 2s ease-in-out infinite; } @keyframes chat-pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.4; } } .chat-header-actions { display: flex; gap: 8px; } .chat-btn-icon { width: 34px; height: 34px; border: none; background: transparent; border-radius: 8px; cursor: pointer; font-size: 1.1em; color: var(--color-text-3); display: flex; align-items: center; justify-content: center; transition: all 0.2s ease; } .chat-btn-icon:hover { background: var(--color-primary-bg); color: var(--color-primary); } /* --- Messages --- */ .chat-messages { flex: 1; overflow-y: auto; padding: 20px; display: flex; flex-direction: column; gap: 16px; scroll-behavior: smooth; } .chat-messages::-webkit-scrollbar { width: 4px; } .chat-messages::-webkit-scrollbar-thumb { background: #d1d5db; border-radius: 2px; } .dark .chat-messages::-webkit-scrollbar-thumb { background: #4b5563; } .chat-msg { display: flex; gap: 12px; max-width: 85%; animation: chat-msg-in 0.3s ease; } @keyframes chat-msg-in { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } } .chat-msg.user { align-self: flex-end; flex-direction: row-reverse; } .chat-msg.assistant { align-self: flex-start; } .chat-msg-avatar { width: 32px; height: 32px; border-radius: 50%; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 0.85em; font-weight: 600; } .chat-msg.user .chat-msg-avatar { background: var(--color-primary); color: #fff; } .chat-msg.assistant .chat-msg-avatar { background: var(--color-primary-bg); color: var(--color-primary); } .chat-msg-bubble { padding: 12px 16px; border-radius: 14px; font-size: 0.92em; line-height: 1.7; word-break: break-word; } .chat-msg.user .chat-msg-bubble { background: var(--color-primary); color: #fff; border-bottom-right-radius: 4px; } .chat-msg.assistant .chat-msg-bubble { background: rgba(0,0,0,0.03); color: var(--color-text-1); border-bottom-left-radius: 4px; } .dark .chat-msg.assistant .chat-msg-bubble { background: rgba(255,255,255,0.04); color: var(--color-text-1); } /* Markdown within messages */ .chat-msg-bubble p { margin: 0.4em 0; } .chat-msg-bubble p:first-child { margin-top: 0; } .chat-msg-bubble p:last-child { margin-bottom: 0; } .chat-msg-bubble code { background: rgba(79,70,229,0.08); padding: 0.15em 0.4em; border-radius: 4px; font-size: 0.88em; color: #7c3aed; } .dark .chat-msg-bubble code { background: rgba(129,140,248,0.12); color: #a5b4fc; } .chat-msg-bubble pre { margin: 0.8em 0; background: #1e1e2e !important; border-radius: 8px; padding: 14px 16px; overflow-x: auto; } .chat-msg-bubble pre code { background: none !important; color: #e2e8f0 !important; padding: 0; font-size: 0.85em; } .chat-msg-bubble ul, .chat-msg-bubble ol { padding-left: 1.5em; margin: 0.4em 0; } .chat-msg-bubble li { margin: 0.2em 0; } .chat-msg-bubble strong { font-weight: 600; } .chat-msg-bubble a { color: var(--color-primary) !important; } /* Thinking indicator */ .chat-thinking { display: flex; gap: 4px; padding: 4px 0; } .chat-thinking span { width: 6px; height: 6px; border-radius: 50%; background: var(--color-text-3); animation: chat-think 1.4s ease-in-out infinite; } .chat-thinking span:nth-child(2) { animation-delay: 0.2s; } .chat-thinking span:nth-child(3) { animation-delay: 0.4s; } @keyframes chat-think { 0%, 80%, 100% { transform: scale(0.6); opacity: 0.4; } 40% { transform: scale(1); opacity: 1; } } /* --- Input --- */ .chat-input-area { padding: 16px 20px; border-top: 1px solid rgba(0,0,0,0.04); flex-shrink: 0; } .dark .chat-input-area { border-color: rgba(255,255,255,0.04); } .chat-input-wrap { display: flex; gap: 8px; align-items: flex-end; } .chat-input { flex: 1; border: 1px solid rgba(0,0,0,0.08); border-radius: 12px; padding: 12px 16px; font-size: 0.92em; font-family: inherit; background: rgba(0,0,0,0.02); color: var(--color-text-1); resize: none; outline: none; line-height: 1.5; max-height: 120px; min-height: 44px; transition: border-color 0.2s, box-shadow 0.2s; } .chat-input:focus { border-color: var(--color-primary); box-shadow: 0 0 0 3px var(--color-primary-bg); } .dark .chat-input { background: rgba(255,255,255,0.04); border-color: rgba(255,255,255,0.08); } .dark .chat-input:focus { border-color: var(--color-primary); box-shadow: 0 0 0 3px rgba(129,140,248,0.12); } .chat-input::placeholder { color: var(--color-text-3); } .chat-send-btn { width: 44px; height: 44px; border: none; border-radius: 12px; background: var(--color-primary); color: #fff; cursor: pointer; font-size: 1.2em; display: flex; align-items: center; justify-content: center; transition: all 0.2s ease; flex-shrink: 0; } .chat-send-btn:hover { background: #4338ca; transform: scale(1.05); } .chat-send-btn:active { transform: scale(0.95); } .chat-send-btn:disabled { opacity: 0.4; cursor: not-allowed; transform: none; } .chat-footer-text { text-align: center; font-size: 0.75em; color: var(--color-text-3); margin-top: 8px; } /* --- Settings Modal --- */ .chat-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.4); z-index: 99999; display: flex; align-items: center; justify-content: center; animation: chat-overlay-in 0.2s ease; } @keyframes chat-overlay-in { from { opacity: 0; } to { opacity: 1; } } .chat-modal { background: var(--color-card); border-radius: 16px; padding: 28px 32px; width: 90%; max-width: 460px; box-shadow: 0 20px 60px rgba(0,0,0,0.15); animation: chat-modal-in 0.3s ease; } @keyframes chat-modal-in { from { opacity: 0; transform: scale(0.95) translateY(10px); } to { opacity: 1; transform: scale(1) translateY(0); } } .chat-modal h2 { font-size: 1.15em; font-weight: 600; color: var(--color-text-1); margin-bottom: 20px; } .chat-modal label { display: block; font-size: 0.85em; font-weight: 500; color: var(--color-text-2); margin-bottom: 6px; margin-top: 16px; } .chat-modal label:first-of-type { margin-top: 0; } .chat-modal input, .chat-modal select { width: 100%; padding: 10px 14px; border: 1px solid rgba(0,0,0,0.08); border-radius: 10px; font-size: 0.9em; font-family: inherit; background: rgba(0,0,0,0.02); color: var(--color-text-1); outline: none; box-sizing: border-box; transition: border-color 0.2s; } .dark .chat-modal input, .dark .chat-modal select { background: rgba(255,255,255,0.04); border-color: rgba(255,255,255,0.08); } .chat-modal input:focus, .chat-modal select:focus { border-color: var(--color-primary); box-shadow: 0 0 0 3px var(--color-primary-bg); } .chat-modal-hint { font-size: 0.78em; color: var(--color-text-3); margin-top: 4px; } .chat-modal-actions { display: flex; gap: 10px; justify-content: flex-end; margin-top: 24px; } .chat-modal-btn { padding: 10px 22px; border-radius: 10px; font-size: 0.9em; font-weight: 500; border: none; cursor: pointer; transition: all 0.2s ease; } .chat-modal-btn.primary { background: var(--color-primary); color: #fff; } .chat-modal-btn.primary:hover { background: #4338ca; } .chat-modal-btn.secondary { background: rgba(0,0,0,0.04); color: var(--color-text-2); } .dark .chat-modal-btn.secondary { background: rgba(255,255,255,0.06); } .chat-modal-btn.secondary:hover { background: rgba(0,0,0,0.08); } .dark .chat-modal-btn.secondary:hover { background: rgba(255,255,255,0.1); } /* --- Welcome screen --- */ .chat-welcome { flex: 1; display: flex; flex-direction: column; align-items: center; justify-content: center; color: var(--color-text-3); text-align: center; padding: 40px 20px; } .chat-welcome-icon { font-size: 3em; margin-bottom: 16px; opacity: 0.5; } .chat-welcome h3 { font-size: 1.2em; font-weight: 600; color: var(--color-text-2); margin-bottom: 8px; } .chat-welcome p { font-size: 0.9em; max-width: 360px; line-height: 1.7; } .chat-welcome-hint { margin-top: 24px; display: flex; flex-direction: column; gap: 8px; width: 100%; max-width: 400px; } .chat-hint-btn { padding: 10px 16px; border: 1px solid rgba(0,0,0,0.06); border-radius: 10px; background: var(--color-card); color: var(--color-text-2); cursor: pointer; font-size: 0.88em; text-align: left; transition: all 0.2s ease; } .dark .chat-hint-btn { border-color: rgba(255,255,255,0.06); } .chat-hint-btn:hover { border-color: var(--color-primary); color: var(--color-primary); background: var(--color-primary-bg); } /* Error toast */ .chat-toast { position: fixed; bottom: 24px; left: 50%; transform: translateX(-50%); background: #ef4444; color: #fff; padding: 10px 20px; border-radius: 10px; font-size: 0.88em; z-index: 999999; animation: chat-toast-in 0.3s ease; box-shadow: 0 4px 16px rgba(239,68,68,0.3); } @keyframes chat-toast-in { from { opacity: 0; transform: translateX(-50%) translateY(10px); } to { opacity: 1; transform: translateX(-50%) translateY(0); } } AI 助手 🗑 ⚙ 💬 开始对话 配置 API 地址和密钥后即可开始与 AI 助手对话。 ⚡ 快速配置 API ↑ 请先配置 API (function() { // ---- State ---- var config = { endpoint: localStorage.getItem('ai_endpoint') || '', key: localStorage.getItem('ai_key') || '', model: localStorage.getItem('ai_model') || 'gpt-4o' }; var messages = []; var isRunning = false; var controller = null; var container = document.getElementById('chatContainer'); var msgEl = document.getElementById('chatMessages'); var welcomeEl = document.getElementById('chatWelcome'); var inputEl = document.getElementById('chatInput'); var sendBtn = document.getElementById('chatSendBtn'); var footerText = document.getElementById('chatFooterText'); // ---- Init ---- function init() { if (config.endpoint && config.key) { inputEl.disabled = false; sendBtn.disabled = false; footerText.textContent = '模型: ' + config.model; } else { footerText.textContent = '请先配置 API'; } } init(); // ---- Auto resize textarea ---- window.autoResize = function(el) { el.style.height = 'auto'; el.style.height = Math.min(el.scrollHeight, 120) + 'px'; }; // ---- Key handlers ---- window.onInputKeydown = function(e) { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); } }; // ---- Scroll to bottom ---- function scrollBottom() { msgEl.scrollTop = msgEl.scrollHeight; } // ---- Add message to UI ---- function addMessage(role, content) { // Remove welcome if (welcomeEl && welcomeEl.parentNode) { welcomeEl.parentNode.removeChild(welcomeEl); } var div = document.createElement('div'); div.className = 'chat-msg ' + role; var avatar = document.createElement('div'); avatar.className = 'chat-msg-avatar'; avatar.textContent = role === 'user' ? 'U' : 'AI'; div.appendChild(avatar); var bubble = document.createElement('div'); bubble.className = 'chat-msg-bubble'; if (role === 'assistant') { bubble.innerHTML = renderMarkdown(content); } else { bubble.textContent = content; } div.appendChild(bubble); msgEl.appendChild(div); scrollBottom(); return bubble; } // ---- Simple Markdown renderer ---- function renderMarkdown(text) { // Escape HTML var html = text .replace(/&/g, '&amp;') .replace(//g, '&gt;'); // Code blocks (fenced) html = html.replace(/```(\w*)
([\s\S]*?)```/g, function(_, lang, code) { return '' + escapeHtml(code.trim()) + ''; }); // Inline code html = html.replace(/`([^`]+)`/g, '$1'); // Bold html = html.replace(/\*\*([^*]+)\*\*/g, '$1'); // Italic html = html.replace(/\*([^*]+)\*/g, '$1'); // Links html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1'); // Line breaks html = html.replace(/

/g, ''); html = html.replace(/
/g, ''); return '' + html + ''; } function escapeHtml(text) { return text.replace(/&/g, '&amp;').replace(//g, '&gt;'); } // ---- Show thinking indicator ---- function showThinking() { var div = document.createElement('div'); div.className = 'chat-msg assistant'; div.id = 'chatThinking'; var avatar = document.createElement('div'); avatar.className = 'chat-msg-avatar'; avatar.textContent = 'AI'; div.appendChild(avatar); var bubble = document.createElement('div'); bubble.className = 'chat-msg-bubble'; bubble.innerHTML = ''; div.appendChild(bubble); msgEl.appendChild(div); scrollBottom(); } function removeThinking() { var el = document.getElementById('chatThinking'); if (el) el.parentNode.removeChild(el); } // ---- Toast ---- function showToast(msg) { var existing = document.querySelector('.chat-toast'); if (existing) existing.parentNode.removeChild(existing); var t = document.createElement('div'); t.className = 'chat-toast'; t.textContent = msg; document.body.appendChild(t); setTimeout(function() { t.parentNode.removeChild(t); }, 4000); } // ---- Send message ---- window.sendMessage = function() { if (isRunning) return; var text = inputEl.value.trim(); if (!text) return; if (!config.endpoint || !config.key) { showToast('请先配置 API 地址和密钥'); return; } // Add user message addMessage('user', text); messages.push({ role: 'user', content: text }); inputEl.value = ''; inputEl.style.height = 'auto'; sendBtn.disabled = true; inputEl.disabled = true; isRunning = true; footerText.textContent = 'AI 思考中...'; showThinking(); // Normalize endpoint var ep = config.endpoint.replace(//+$/, ''); if (!ep.endsWith('/v1')) ep = ep + '/v1'; controller = new AbortController(); fetch(ep + '/chat/completions', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.key }, body: JSON.stringify({ model: config.model, messages: messages, stream: true }), signal: controller.signal }).then(function(resp) { if (!resp.ok) { return resp.text().then(function(t) { throw new Error('HTTP ' + resp.status + ': ' + t); }); } removeThinking(); var reader = resp.body.getReader(); var decoder = new TextDecoder(); var buffer = ''; var fullContent = ''; var assistantBubble = addMessage('assistant', '...'); function readChunk() { reader.read().then(function(result) { if (result.done) { messages.push({ role: 'assistant', content: fullContent }); isRunning = false; sendBtn.disabled = false; inputEl.disabled = false; inputEl.focus(); footerText.textContent = '模型: ' + config.model; return; } buffer += decoder.decode(result.value, { stream: true }); var lines = buffer.split('
'); buffer = lines.pop() || ''; for (var i = 0; i < lines.length; i++) { var line = lines[i].trim(); if (line.startsWith('data: ')) { var data = line.slice(6); if (data === '[DONE]') continue; try { var json = JSON.parse(data); var delta = json.choices && json.choices[0] && json.choices[0].delta; if (delta && delta.content) { fullContent += delta.content; assistantBubble.innerHTML = renderMarkdown(fullContent); scrollBottom(); } } catch(e) {} } } readChunk(); }).catch(function(err) { if (err.name === 'AbortError') return; removeThinking(); isRunning = false; sendBtn.disabled = false; inputEl.disabled = false; footerText.textContent = '模型: ' + config.model; showToast('请求失败: ' + err.message); }); } readChunk(); }).catch(function(err) { removeThinking(); isRunning = false; sendBtn.disabled = false; inputEl.disabled = false; footerText.textContent = '模型: ' + config.model; if (err.name === 'AbortError') return; showToast('连接失败: ' + err.message); }); }; // ---- Clear chat ---- window.clearChat = function() { if (isRunning) { if (controller) controller.abort(); isRunning = false; sendBtn.disabled = !(!inputEl.disabled); } // Remove all messages var msgs = msgEl.querySelectorAll('.chat-msg'); msgs.forEach(function(el) { el.parentNode.removeChild(el); }); messages = []; // Restore welcome if (!document.getElementById('chatWelcome')) { var w = document.createElement('div'); w.className = 'chat-welcome'; w.id = 'chatWelcome'; w.innerHTML = '💬' + '开始对话' + '配置 API 地址和密钥后即可开始与 AI 助手对话。' + '' + '⚡ 快速配置 API' + ''; msgEl.appendChild(w); } inputEl.disabled = !(config.endpoint && config.key); sendBtn.disabled = !(config.endpoint && config.key); inputEl.value = ''; footerText.textContent = config.endpoint && config.key ? '模型: ' + config.model : '请先配置 API'; }; // ---- Settings ---- var settingsShown = false; window.showSettings = function() { if (settingsShown) return; settingsShown = true; var overlay = document.createElement('div'); overlay.className = 'chat-overlay'; overlay.id = 'chatSettingsOverlay'; overlay.addEventListener('click', function(e) { if (e.target === overlay) closeSettings(); }); overlay.innerHTML = '' + '⚙ API 配置' + 'API 地址' + '' + '支持 OpenAI 兼容接口，如 https://api.openai.com' + 'API 密钥' + '' + '模型' + '' + '如 gpt-4o、gpt-4o-mini、deepseek-chat 等' + '' + '取消' + '保存' + '' + ''; document.body.appendChild(overlay); }; function escapeAttr(s) { return s.replace(/"/g, '&quot;').replace(//g, '&gt;'); } window.closeSettings = function() { settingsShown = false; var o = document.getElementById('chatSettingsOverlay'); if (o) o.parentNode.removeChild(o); }; window.saveSettings = function() { var ep = document.getElementById('cfgEndpoint').value.trim(); var key = document.getElementById('cfgKey').value.trim(); var model = document.getElementById('cfgModel').value.trim() || 'gpt-4o'; config.endpoint = ep; config.key = key; config.model = model; localStorage.setItem('ai_endpoint', ep); localStorage.setItem('ai_key', key); localStorage.setItem('ai_model', model); closeSettings(); init(); if (ep && key) { showToast('配置已保存'); } }; window.quickStart = function() { showSettings(); }; })();
